#!/usr/bin/env python3
from __future__ import annotations
from pathlib import Path

ROOT = Path(__file__).resolve().parents[1]
DOCS = ROOT / "docs"

HTML = r'''<!doctype html>
<html lang="ko">
<head>
  <meta charset="utf-8" />
  <meta name="viewport" content="width=device-width, initial-scale=1" />
  <title>넥슨 글로벌 피어 주가·시총·뉴스 대시보드</title>
  <script src="https://cdn.jsdelivr.net/npm/chart.js@4.4.1/dist/chart.umd.min.js"></script>
  <style>
    :root{--bg:#0b1020;--panel:#121a2f;--panel2:#17213a;--soft:#0f172a;--text:#eef2ff;--muted:#9aa7c7;--line:#25304d;--accent:#7dd3fc;--nexon:#8b5cf6;--good:#34d399;--bad:#fb7185;--warn:#fbbf24;--shadow:0 18px 40px rgba(0,0,0,.24)}
    body.light{--bg:#f5f7fb;--panel:#fff;--panel2:#edf2f7;--soft:#f8fafc;--text:#111827;--muted:#64748b;--line:#d5deee;--accent:#0369a1;--nexon:#6d28d9;--good:#059669;--bad:#e11d48;--warn:#b45309;--shadow:0 14px 28px rgba(15,23,42,.08)}
    *{box-sizing:border-box} html{scroll-behavior:smooth} body{margin:0;background:radial-gradient(circle at top left,rgba(125,211,252,.14),transparent 30%),var(--bg);color:var(--text);font-family:-apple-system,BlinkMacSystemFont,"Segoe UI",sans-serif}.wrap{max-width:1520px;margin:auto;padding:24px 18px 70px}.top{position:sticky;top:0;z-index:30;background:linear-gradient(180deg,var(--bg) 75%,transparent);backdrop-filter:blur(12px);padding:12px 0 14px}.topline{display:flex;justify-content:space-between;align-items:center;gap:16px}.brand h1{font-size:29px;margin:0}.brand .meta{color:var(--muted);font-size:13px;margin-top:7px}.actions{display:flex;gap:8px;flex-wrap:wrap}button,a.btn{border:1px solid var(--line);background:var(--panel);color:var(--text);border-radius:12px;padding:10px 13px;cursor:pointer;text-decoration:none;font-weight:800}button:hover,a.btn:hover{border-color:var(--accent)}.tabs{display:flex;gap:8px;margin-top:14px;overflow:auto}.tab{white-space:nowrap}.tab.active{background:linear-gradient(135deg,var(--accent),var(--nexon));color:white;border-color:transparent}.section{display:none}.section.active{display:block}.cards{display:grid;grid-template-columns:repeat(5,minmax(0,1fr));gap:13px;margin:18px 0}.card{background:linear-gradient(180deg,var(--panel),var(--panel2));border:1px solid var(--line);border-radius:18px;padding:15px;box-shadow:var(--shadow)}.card.nexon{border:2px solid var(--nexon);box-shadow:0 0 0 4px rgba(139,92,246,.12),var(--shadow)}.k{color:var(--muted);font-size:12px}.v{font-size:24px;font-weight:900;margin-top:7px;letter-spacing:-.02em}.sub{color:var(--muted);font-size:12px;margin-top:6px;line-height:1.45}.grid{display:grid;grid-template-columns:1.15fr .85fr;gap:14px}.grid3{display:grid;grid-template-columns:repeat(3,1fr);gap:14px}.chartbox{height:380px}.toolbar{position:sticky;top:92px;z-index:25;display:grid;grid-template-columns:1.4fr repeat(3,minmax(145px,.45fr));gap:9px;margin:16px 0;padding:10px;background:rgba(15,23,42,.76);border:1px solid var(--line);border-radius:16px;backdrop-filter:blur(12px)}body.light .toolbar{background:rgba(248,250,252,.82)}.toolbar input,.toolbar select{width:100%;background:var(--panel);color:var(--text);border:1px solid var(--line);border-radius:12px;padding:11px}.table-wrap{overflow:visible;border-radius:18px;border:1px solid var(--line);background:var(--panel)}table{width:100%;border-collapse:separate;border-spacing:0;min-width:1180px}th,td{padding:12px 10px;border-bottom:1px solid var(--line);text-align:right;font-size:13px;vertical-align:middle}th{position:sticky;top:154px;z-index:20;background:#e9eef5;color:#63738b;font-weight:900;font-size:16px}body:not(.light) th{background:#111b30;color:#b6c3dd}td:first-child,th:first-child{text-align:left}.name{font-weight:900}.small{display:block;color:var(--muted);font-size:12px;margin-top:3px}.up{color:var(--good);font-weight:900}.down{color:var(--bad);font-weight:900}.pill{display:inline-flex;border:1px solid var(--line);border-radius:999px;padding:4px 9px;font-size:12px;color:var(--muted);background:rgba(125,211,252,.07)}tr.nexon-row td{background:rgba(139,92,246,.14);border-top:1px solid rgba(139,92,246,.55);border-bottom:1px solid rgba(139,92,246,.55)}tr.nexon-row td:first-child{border-left:4px solid var(--nexon)}.status-ok{color:var(--good)}.news-list{display:grid;grid-template-columns:repeat(2,minmax(0,1fr));gap:12px}.news{padding:13px;border:1px solid var(--line);border-radius:15px;background:var(--soft)}.news a{color:var(--accent);font-weight:900;text-decoration:none}.news p{color:var(--muted);line-height:1.45;margin:8px 0 0;font-size:13px}.compare-grid{display:grid;grid-template-columns:1fr 1fr;gap:14px}.foot{color:var(--muted);font-size:12px;line-height:1.6;margin-top:16px}.hide{display:none!important}@media(max-width:1100px){.cards{grid-template-columns:repeat(2,1fr)}.grid,.grid3,.compare-grid{grid-template-columns:1fr}.toolbar{grid-template-columns:1fr 1fr;top:116px}th{top:190px}.news-list{grid-template-columns:1fr}.topline{display:block}.actions{margin-top:12px}}@media(max-width:640px){.cards,.toolbar{grid-template-columns:1fr}.wrap{padding:12px 8px}.brand h1{font-size:22px}th,td{font-size:12px;padding:9px 7px}.v{font-size:20px}}
  </style>
</head>
<body>
<div class="wrap">
  <header class="top">
    <div class="topline"><div class="brand"><h1>넥슨 글로벌 피어 대시보드</h1><div class="meta" id="topMeta">주가·시총·재무 아카이브·뉴스를 한 화면에서 비교</div></div><div class="actions"><button id="themeBtn">라이트/다크</button><button id="refreshBtn">데이터 새로고침</button><a class="btn" href="data/market_quotes.csv" download>CSV 다운로드</a></div></div>
    <nav class="tabs"><button class="tab active" data-page="overview">종합 상황판</button><button class="tab" data-page="peer">플랫폼사 vs 게임사</button><button class="tab" data-page="finance">재무성과 BD</button><button class="tab" data-page="news">기업 뉴스</button></nav>
  </header>

  <section id="overview" class="section active"><div class="cards" id="cards"></div><div class="grid"><div class="card chartbox"><canvas id="capChart"></canvas></div><div class="card chartbox"><canvas id="countryChart"></canvas></div></div><div class="toolbar"><input id="search" placeholder="회사명/티커/국가/거래소 검색"><select id="country"><option value="">전체 국가</option></select><select id="category"><option value="">전체 유형</option></select><select id="sort"><option value="market_cap_krw_desc">시총 KRW 높은순</option><option value="change_percent_desc">상승률 높은순</option><option value="change_percent_asc">하락률 높은순</option><option value="company_ko_asc">회사명 가나다순</option></select></div><div class="table-wrap"><table id="tbl"><thead><tr><th>회사</th><th>유형</th><th>국가/거래소</th><th>티커</th><th>현재가</th><th>등락률</th><th>시총 현지통화</th><th>시총 KRW</th><th>거래량</th><th>업데이트</th><th>상태</th></tr></thead><tbody></tbody></table></div></section>
  <section id="peer" class="section"><div class="compare-grid"><div class="card chartbox"><canvas id="platformChart"></canvas></div><div class="card chartbox"><canvas id="gameChart"></canvas></div></div><div class="grid3" id="peerCards" style="margin-top:14px"></div></section>
  <section id="finance" class="section"><div class="card"><h2>재무성과 BD 아카이브</h2><p class="sub">Google Sheets의 과거 재무성과 시트와 연결했습니다. 현재 대시보드에서는 2026 Q1 매출/영업이익과 시총을 함께 비교합니다.</p><div class="table-wrap"><table id="finTbl"><thead><tr><th>회사</th><th>티커</th><th>2026 Q1 매출</th><th>2026 Q1 영업이익</th><th>현재 시총 KRW</th><th>자료</th></tr></thead><tbody></tbody></table></div></div></section>
  <section id="news" class="section"><div class="card"><h2>최근 기업 관련 기사</h2><p class="sub">기사 DB에서 회사명·브랜드·주요 IP 키워드로 매칭한 최근 기사입니다.</p><div class="toolbar" style="position:static;margin:12px 0"><input id="newsSearch" placeholder="뉴스 검색: 넥슨, Nintendo, Tencent, Xbox 등"><select id="newsCompany"><option value="">전체 회사</option></select></div><div class="news-list" id="newsList"></div></div></section>
  <div class="foot" id="foot"></div>
</div>
<script>
let RAW=[], META={}, ARCH={financial_archive:{rows:[]},news_archive:{rows:[]}}, charts={}; const KRW_EOK=100000000, KRW_JO=1000000000000;
function n(v){return Number(v||0)} function fmtNum(v,d=0){return (v==null||!isFinite(Number(v)))?'-':Number(v).toLocaleString('ko-KR',{maximumFractionDigits:d,minimumFractionDigits:d})}
function fmtKrw(v){v=n(v); if(!v)return '-'; if(Math.abs(v)>=KRW_JO){let jo=Math.floor(v/KRW_JO), eok=Math.round((v-jo*KRW_JO)/KRW_EOK); return eok?`${fmtNum(jo)}조 ${fmtNum(eok)}억 원`:`${fmtNum(jo)}조 원`;} return `${fmtNum(v/KRW_EOK,0)}억 원`;}
function fmtCapLocal(v,cur){if(!v)return '-'; const unit=(cur==='KRW'||cur==='JPY')?KRW_EOK:1000000, label=(cur==='KRW'||cur==='JPY')?'억':'M'; return `${fmtNum(v/unit,1)} ${label} ${cur}`}
function fmtPrice(v,cur){return v==null?'-':`${fmtNum(v,(cur==='JPY'||cur==='KRW')?0:2)} ${cur||''}`} function pct(v){if(v==null||!isFinite(Number(v)))return '-'; return `<span class="${v>=0?'up':'down'}">${v>=0?'+':''}${fmtNum(v,2)}%</span>`} function dt(s){try{return new Date(s).toLocaleString('ko-KR',{timeZone:'Asia/Seoul'})}catch(e){return s||'-'}}
function filtered(){const q=search.value.trim().toLowerCase(), c=country.value, cat=category.value, sort=document.getElementById('sort').value;let rows=RAW.filter(r=>(!c||r.country===c)&&(!cat||r.category===cat)&&(!q||[r.company_ko,r.company_en,r.yahoo_symbol,r.input_ticker,r.country,r.exchange,r.category].join(' ').toLowerCase().includes(q)));rows.sort((a,b)=>sort==='market_cap_krw_desc'?n(b.market_cap_krw)-n(a.market_cap_krw):sort==='change_percent_desc'?n(b.change_percent)-n(a.change_percent):sort==='change_percent_asc'?n(a.change_percent)-n(b.change_percent):String(a.company_ko).localeCompare(String(b.company_ko),'ko'));return rows}
function rankInGroup(row){let peers=RAW.filter(r=>r.category===row.category&&r.market_cap_krw).sort((a,b)=>n(b.market_cap_krw)-n(a.market_cap_krw));return peers.findIndex(r=>r.company_ko===row.company_ko)+1}
function renderCards(rows){const ok=rows.filter(r=>r.data_status==='ok'), total=ok.reduce((s,r)=>s+n(r.market_cap_krw),0), nexon=RAW.find(r=>r.company_ko==='넥슨'), game=RAW.filter(r=>r.category==='게임사'), platform=RAW.filter(r=>r.category==='플랫폼사');cards.innerHTML=`<div class="card nexon"><div class="k">NEXON 하이라이트</div><div class="v">${fmtKrw(nexon?.market_cap_krw)}</div><div class="sub">게임사 내 시총 ${rankInGroup(nexon)}위 · ${pct(nexon?.change_percent)}</div></div><div class="card"><div class="k">표시 기업</div><div class="v">${rows.length}개</div><div class="sub">정상 시총 ${ok.length}개 / 전체 ${META.company_count||RAW.length}개</div></div><div class="card"><div class="k">합산 시가총액</div><div class="v">${fmtKrw(total)}</div><div class="sub">고정 환율 KRW 환산</div></div><div class="card"><div class="k">플랫폼사 합산</div><div class="v">${fmtKrw(platform.reduce((s,r)=>s+n(r.market_cap_krw),0))}</div><div class="sub">Alphabet · Apple · Microsoft</div></div><div class="card"><div class="k">게임사 합산</div><div class="v">${fmtKrw(game.reduce((s,r)=>s+n(r.market_cap_krw),0))}</div><div class="sub">플랫폼 3사 제외</div></div>`}
function renderTable(rows){document.querySelector('#tbl tbody').innerHTML=rows.map(r=>`<tr class="${r.company_ko==='넥슨'?'nexon-row':''}"><td><span class="name">${r.company_ko}${r.company_ko==='넥슨'?' ★':''}</span><span class="small">${r.company_en}</span></td><td><span class="pill">${r.category}</span></td><td>${r.country}<span class="small">${r.exchange}</span></td><td>${r.input_ticker}<span class="small">${r.yahoo_symbol}</span></td><td>${fmtPrice(r.price,r.currency)}</td><td>${pct(r.change_percent)}</td><td>${fmtCapLocal(r.market_cap_local,r.currency)}</td><td><b>${fmtKrw(r.market_cap_krw)}</b></td><td>${fmtNum(r.volume,0)}</td><td>${dt(r.market_time||r.as_of_utc)}</td><td class="${r.data_status==='ok'?'status-ok':'status-error'}">${r.data_status}</td></tr>`).join('')}
function makeChart(id,type,data,opt={}){if(charts[id])charts[id].destroy();charts[id]=new Chart(document.getElementById(id),{type,data,options:Object.assign({responsive:true,maintainAspectRatio:false,plugins:{legend:{labels:{color:getComputedStyle(document.body).getPropertyValue('--text')}}},scales:type==='doughnut'?{}:{x:{ticks:{color:getComputedStyle(document.body).getPropertyValue('--muted')}},y:{ticks:{color:getComputedStyle(document.body).getPropertyValue('--muted')}}}},opt)})}
function renderCharts(rows){let ok=rows.filter(r=>r.market_cap_krw).sort((a,b)=>n(b.market_cap_krw)-n(a.market_cap_krw)).slice(0,20);makeChart('capChart','bar',{labels:ok.map(r=>r.company_ko),datasets:[{label:'시총 KRW(조)',data:ok.map(r=>+(n(r.market_cap_krw)/KRW_JO).toFixed(1)),backgroundColor:ok.map(r=>r.company_ko==='넥슨'?'#8b5cf6':r.category==='플랫폼사'?'#38bdf8':'#34d399')}]},{indexAxis:'y'});let by={};rows.filter(r=>r.market_cap_krw).forEach(r=>by[r.country]=(by[r.country]||0)+n(r.market_cap_krw));let ents=Object.entries(by).sort((a,b)=>b[1]-a[1]);makeChart('countryChart','doughnut',{labels:ents.map(e=>e[0]),datasets:[{data:ents.map(e=>+(e[1]/KRW_JO).toFixed(1)),backgroundColor:['#7dd3fc','#34d399','#fbbf24','#fb7185','#a78bfa','#f472b6','#60a5fa','#94a3b8']}]} )}
function renderPeer(){['플랫폼사','게임사'].forEach((cat,i)=>{let id=i?'gameChart':'platformChart', rows=RAW.filter(r=>r.category===cat&&r.market_cap_krw).sort((a,b)=>n(b.market_cap_krw)-n(a.market_cap_krw)).slice(0,i?15:3);makeChart(id,'bar',{labels:rows.map(r=>r.company_ko),datasets:[{label:`${cat} 시총 KRW(조)`,data:rows.map(r=>+(n(r.market_cap_krw)/KRW_JO).toFixed(1)),backgroundColor:rows.map(r=>r.company_ko==='넥슨'?'#8b5cf6':i?'#34d399':'#38bdf8')}]},{indexAxis:'y'});});let nexon=RAW.find(r=>r.company_ko==='넥슨');peerCards.innerHTML=`<div class="card nexon"><div class="k">넥슨 게임사 순위</div><div class="v">${rankInGroup(nexon)}위</div><div class="sub">플랫폼 3사 제외 게임사끼리 비교</div></div>`+['플랫폼사','게임사'].map(cat=>{let rs=RAW.filter(r=>r.category===cat), up=rs.filter(r=>n(r.change_percent)>0).length;return `<div class="card"><div class="k">${cat}</div><div class="v">${rs.length}개</div><div class="sub">상승 ${up}개 · 합산 ${fmtKrw(rs.reduce((s,r)=>s+n(r.market_cap_krw),0))}</div></div>`}).join('')}
function renderFinance(){let rows=(ARCH.financial_archive?.rows||[]), qmap=Object.fromEntries(RAW.map(r=>[r.company_en,r]));finTbl.querySelector('tbody').innerHTML=rows.map(r=>{let live=RAW.find(x=>x.company_en===r.company||x.company_ko===r.company||x.input_ticker===r.ticker);return `<tr class="${(live?.company_ko==='넥슨'||r.company==='넥슨')?'nexon-row':''}"><td><b>${live?.company_ko||r.company}</b><span class="small">${r.company}</span></td><td>${r.ticker||live?.input_ticker||''}</td><td>${r.q1_revenue_krw_label||'-'}</td><td>${r.q1_operating_profit_krw_label||'-'}</td><td>${fmtKrw(live?.market_cap_krw)}</td><td>${r.source_link?`<a class="btn" href="${r.source_link}" target="_blank" rel="noopener noreferrer">원문</a>`:'-'}</td></tr>`}).join('')}
function renderNews(){let q=(newsSearch?.value||'').toLowerCase(), co=newsCompany?.value||'', rows=(ARCH.news_archive?.rows||[]).filter(r=>(!co||r.company===co)&&(!q||[r.company,r.title,r.original_title,r.summary,r.keyword].join(' ').toLowerCase().includes(q))).slice(0,60);newsList.innerHTML=rows.map(r=>`<article class="news ${r.company==='넥슨'?'nexon':''}"><span class="pill">${r.company}</span> <span class="small">${r.published_at||''}</span><h3><a href="${r.url}" target="_blank" rel="noopener noreferrer">${r.title||r.original_title}</a></h3><p>${r.summary||''}</p></article>`).join('')||'<p class="sub">매칭된 기사가 없습니다.</p>'}
function refresh(){let rows=filtered();renderCards(rows);renderTable(rows);renderCharts(rows);renderPeer();renderFinance();renderNews();topMeta.textContent=`최종 갱신 ${dt(META.generated_at_utc)} · 정상 시총 ${META.ok_count}/${META.company_count} · 기사 ${ARCH.news_archive?.count||0}건 연동`;foot.innerHTML=`무료/지연 시세 기반 참고용 데이터입니다. 투자 판단용 실시간 호가가 아닙니다. KRW 환산은 고정 환율(USD 1,460 / EUR 1,720 / JPY 9 / CNY 200 / HKD 190 / TWD 45 / SEK 150 / THB 45)을 적용합니다.`}
async function load(){META=await (await fetch('data/market_quotes.json?ts='+Date.now())).json();RAW=META.rows||[];try{ARCH=await (await fetch('data/archives.json?ts='+Date.now())).json()}catch(e){}['country','category'].forEach(id=>{let sel=document.getElementById(id);[...new Set(RAW.map(r=>r[id]).filter(Boolean))].sort().forEach(v=>sel.insertAdjacentHTML('beforeend',`<option value="${v}">${v}</option>`))});[...new Set((ARCH.news_archive?.rows||[]).map(r=>r.company).filter(Boolean))].sort().forEach(v=>newsCompany.insertAdjacentHTML('beforeend',`<option value="${v}">${v}</option>`));refresh()}
document.querySelectorAll('.tab').forEach(b=>b.onclick=()=>{document.querySelectorAll('.tab,.section').forEach(x=>x.classList.remove('active'));b.classList.add('active');document.getElementById(b.dataset.page).classList.add('active');setTimeout(refresh,50)});themeBtn.onclick=()=>{document.body.classList.toggle('light');setTimeout(refresh,50)};refreshBtn.onclick=()=>location.reload();['search','country','category','sort','newsSearch','newsCompany'].forEach(id=>document.getElementById(id)?.addEventListener('input',refresh));load().catch(e=>foot.textContent='데이터 로드 실패: '+e);
</script>
</body></html>'''
DOCS.mkdir(parents=True, exist_ok=True)
(DOCS / "index.html").write_text(HTML, encoding="utf-8")
(DOCS / ".nojekyll").write_text("", encoding="utf-8")
print(DOCS / "index.html")
